API_name: nchu_course_get_weekly_content
Description:
{
  "description": "取得特定課程的每週授課內容。回傳包含每週授課內容的 JSON 字串",
  "required_parameters": [
    {
      "name": "course_id",
      "type": "STRING",
      "description": "課程 ID（選課號碼，例如：2294）"
    }
  ],
  "optional_parameters": [
    {
      "name": "semester",
      "type": "STRING",
      "description": "學年期代碼。若未指定，則使用最新學期。",
      "default": null
    }
  ]
}

